'use client';

import React from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';
import { PRODUCT_HERO_THEMES } from '@/lib/themes/product-hero-themes';
import { IconPicker, IconConfig, IconButton } from '@/components/ui/IconPicker';
